"use strict";parserFactory.register("www.8muses.com",()=>new EightMusesParser),parserFactory.register("comics.8muses.com",()=>new EightMusesParser);class EightMusesParserImageCollector extends ImageCollector{constructor(){super()}initialUrlToTry(e){return e.sourceUrl.replace(/\/th\//,"/fl/")}}class EightMusesParser extends Parser{constructor(){super(new EightMusesParserImageCollector)}async getChapterUrls(e){return[...e.querySelectorAll("div.gallery a")].map(e=>util.hyperLinkToChapter(e)).filter(e=>!util.isNullOrEmpty(e.title))}findContent(e){let r=e.querySelector("div#content");for(let e of r.querySelectorAll("img"))""===e.src&&(e.src=e.getAttribute("data-src"));return r}removeOldPages(e){for(let r of[...e.querySelectorAll("a")]){let e=r.href.split("/");parseInt(e[e.length-1])<63&&r.remove()}}findCoverImageUrl(){return null}}